mapper.select:
SELECT t.id, t.process_codes, t.process_name, t.technique_name, t.technique_code, t.cargo_codes, t.cargo_names, t.status, t.create_by, t.create_time, t.update_by, t.update_time, s.user_name as create_by_name, a.user_name as update_by_name FROM m_operation_technology t inner join sys_user s on t.create_by = s.id left join sys_user a on t.update_by = a.id where 1=1
and process_name like #{processName}
and process_codes=#{code}
order by CREATE_TIME desc

SELECT t.id, t.process_codes, t.process_name, t.technique_name, t.technique_code, t.cargo_codes, t.cargo_names, t.status, t.create_by, t.create_time, t.update_by, t.update_time, s.user_name as create_by_name, a.user_name as update_by_name FROM m_operation_technology t inner join sys_user s on t.create_by = s.id left join sys_user a on t.update_by = a.id
and technique_name like #{techniqueName}
and process_codes=#{code}
order by CREATE_TIME desc

mapper.delete:
DELETE FROM m_operation_technology_machine
WHERE 1=1

    and technology_id=#{id}

DELETE FROM m_operation_technology_worker
WHERE 1=1

    and technology_id=#{id}

DELETE FROM m_operation_technology_workwar
WHERE 1=1

    and technology_id=#{id}
